/** Resolve a user preference (including "system") to a concrete theme. */
export function resolveTheme(
  pref: ThemePreference,
  systemDark: boolean,
): BuiltInTheme {
  if (pref === "system") {
    return BUILT_IN_THEMES[systemDark ? "t3-dark" : "t3-light"];
  }
  return BUILT_IN_THEMES[pref];
