/**
 * Theme system — shared type definitions and built-in palette data.
 * Plain TypeScript (no Effect), safe to import from both server and web.
 */

/** All color tokens that define a complete UI theme. */
export interface ThemeColorTokens {
  // Core surfaces
  background: string;
  foreground: string;
  card: string;
  cardForeground: string;
  popover: string;
  popoverForeground: string;
  // Brand / interactive
  primary: string;
  primaryForeground: string;
  secondary: string;
  secondaryForeground: string;
  muted: string;
  mutedForeground: string;
  accent: string;
  accentForeground: string;
  // Borders and inputs
  border: string;
  input: string;
  ring: string;
  // Semantic status
  destructive: string;
  destructiveForeground: string;
  info: string;
  infoForeground: string;
  success: string;
  successForeground: string;
  warning: string;
  warningForeground: string;
  // App-specific areas
  sidebar: string;
  sidebarForeground: string;
  sidebarBorder: string;
}

export type BuiltInThemeName = "t3-light" | "t3-dark" | "t3-midnight";

export type ThemePreference = BuiltInThemeName | "system";

export interface BuiltInTheme {
  name: BuiltInThemeName;
  label: string;
  isDark: boolean;
  tokens: ThemeColorTokens;
}

export const BUILT_IN_THEMES: Record<BuiltInThemeName, BuiltInTheme> = {
  "t3-light": {
    name: "t3-light",
    label: "Light",
    isDark: false,
    tokens: {
      background: "#ffffff",
      foreground: "#262626",
      card: "#ffffff",
      cardForeground: "#262626",
      popover: "#ffffff",
      popoverForeground: "#262626",
      primary: "oklch(0.488 0.217 264)",
      primaryForeground: "#ffffff",
      secondary: "rgba(0, 0, 0, 0.04)",
      secondaryForeground: "#262626",
      muted: "rgba(0, 0, 0, 0.04)",
      mutedForeground: "#737373",
      accent: "rgba(0, 0, 0, 0.04)",
      accentForeground: "#262626",
      border: "rgba(0, 0, 0, 0.08)",
      input: "rgba(0, 0, 0, 0.10)",
      ring: "oklch(0.488 0.217 264)",
      destructive: "#ef4444",
      destructiveForeground: "#b91c1c",
      info: "#3b82f6",
      infoForeground: "#1d4ed8",
      success: "#10b981",
      successForeground: "#047857",
      warning: "#f59e0b",
      warningForeground: "#b45309",
      sidebar: "#f9fafb",
      sidebarForeground: "#262626",
      sidebarBorder: "rgba(0, 0, 0, 0.08)",
    },
  },

  "t3-dark": {
    name: "t3-dark",
    label: "Dark",
    isDark: true,
    tokens: {
      background: "#0d0d0d",
      foreground: "#f5f5f5",
      card: "#111111",
      cardForeground: "#f5f5f5",
      popover: "#111111",
      popoverForeground: "#f5f5f5",
      primary: "oklch(0.588 0.217 264)",
      primaryForeground: "#ffffff",
      secondary: "rgba(255, 255, 255, 0.04)",
      secondaryForeground: "#f5f5f5",
      muted: "rgba(255, 255, 255, 0.04)",
      mutedForeground: "#7a7a7a",
      accent: "rgba(255, 255, 255, 0.04)",
      accentForeground: "#f5f5f5",
      border: "rgba(255, 255, 255, 0.06)",
      input: "rgba(255, 255, 255, 0.08)",
      ring: "oklch(0.588 0.217 264)",
      destructive: "#f87171",
      destructiveForeground: "#fca5a5",
      info: "#3b82f6",
      infoForeground: "#60a5fa",
      success: "#10b981",
      successForeground: "#34d399",
      warning: "#f59e0b",
      warningForeground: "#fbbf24",
      sidebar: "#0a0a0a",
      sidebarForeground: "#f5f5f5",
      sidebarBorder: "rgba(255, 255, 255, 0.06)",
    },
  },

  "t3-midnight": {
    name: "t3-midnight",
    label: "Midnight",
    isDark: true,
    tokens: {
      background: "#020817",
      foreground: "#e2e8f0",
      card: "#0f172a",
      cardForeground: "#e2e8f0",
      popover: "#0f172a",
      popoverForeground: "#e2e8f0",
      primary: "oklch(0.65 0.22 264)",
      primaryForeground: "#ffffff",
      secondary: "rgba(148, 163, 184, 0.08)",
      secondaryForeground: "#e2e8f0",
      muted: "rgba(148, 163, 184, 0.08)",
      mutedForeground: "#64748b",
      accent: "rgba(148, 163, 184, 0.08)",
      accentForeground: "#e2e8f0",
      border: "rgba(148, 163, 184, 0.12)",
      input: "rgba(148, 163, 184, 0.15)",
      ring: "oklch(0.65 0.22 264)",
      destructive: "#f87171",
      destructiveForeground: "#fca5a5",
      info: "#60a5fa",
      infoForeground: "#93c5fd",
      success: "#34d399",
      successForeground: "#6ee7b7",
      warning: "#fbbf24",
      warningForeground: "#fcd34d",
      sidebar: "#010b14",
      sidebarForeground: "#e2e8f0",
      sidebarBorder: "rgba(148, 163, 184, 0.12)",
    },
  },
};

/**
 * Resolve a theme preference to a concrete BuiltInTheme.
 * When preference is "system", falls back to t3-dark or t3-light based on
 * the caller-supplied systemDark flag.
 */
export function resolveTheme(preference: ThemePreference, systemDark: boolean): BuiltInTheme {
  if (preference === "system") {
    return systemDark ? BUILT_IN_THEMES["t3-dark"] : BUILT_IN_THEMES["t3-light"];
  }
  return BUILT_IN_THEMES[preference];
}

