import type { ReactNode } from "react";

import { useTheme } from "../hooks/useTheme";

/**
 * Subscribes to the external theme store so the DOM stays in sync while the
 * React tree is mounted.  Add this to the Wrap stack in router.ts — it renders
 * no markup of its own.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  useTheme();
  return <>{children}</>;
}

