import { BUILT_IN_THEMES, type ThemePreference } from "@t3tools/shared/theme";

import { useTheme } from "../hooks/useTheme";

const THEME_OPTIONS: Array<{
  value: ThemePreference;
  label: string;
  description: string;
}> = [
  {
    value: "system",
    label: "System",
    description: "Match your OS appearance setting.",
  },
  {
    value: "t3-light",
    label: "Light",
    description: "Always use the light theme.",
  },
  {
    value: "t3-dark",
    label: "Dark",
    description: "Always use the dark theme.",
  },
  {
    value: "t3-midnight",
    label: "Midnight",
    description: "Deep navy dark theme.",
  },
];

/**
 * Theme picker with per-theme color swatches.  Reads and writes the global
 * theme preference through useTheme.
 */
export function ThemeSelector() {
  const { theme, setTheme, resolvedThemeData } = useTheme();

  return (
    <div className="space-y-2">
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {THEME_OPTIONS.map((option) => {
          const selected = theme === option.value;
          const themeData = option.value !== "system" ? BUILT_IN_THEMES[option.value] : null;

          return (
            <button
              key={option.value}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setTheme(option.value)}
            >
              <span className="flex flex-col">
                <span className="text-sm font-medium">{option.label}</span>
                <span className="text-xs">{option.description}</span>
              </span>

              <div className="flex shrink-0 items-center gap-2">
                {themeData !== null && (
                  <div className="flex gap-0.5" aria-hidden="true">
                    <span
                      className="block size-3 rounded-full border border-black/10"
                      style={{ background: themeData.tokens.background }}
                    />
                    <span
                      className="block size-3 rounded-full border border-black/10"
                      style={{ background: themeData.tokens.primary }}
                    />
                    <span
                      className="block size-3 rounded-full border border-black/10"
                      style={{ background: themeData.tokens.sidebar }}
                    />
                  </div>
                )}

                {selected && (
                  <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                    Selected
                  </span>
                )}
              </div>
            </button>
          );
        })}
      </div>

      <p className="mt-2 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{resolvedThemeData.label}</span>
      </p>
    </div>
  );
}

