1	import { useCallback, useEffect, useSyncExternalStore } from "react";
2	
3	import {
4	  type BuiltInTheme,
5	  type BuiltInThemeName,
6	  type ThemeColorTokens,
7	  type ThemePreference,
8	  resolveTheme,
9	} from "@t3tools/shared/theme";
10	
11	const STORAGE_KEY = "t3code:theme";
12	const MEDIA_QUERY = "(prefers-color-scheme: dark)";
13	
14	/**
15	 * Maps each ThemeColorTokens field to the corresponding CSS custom property
16	 * name so we can apply them all as inline styles on <html>.
17	 */
18	const CSS_VAR_MAP: Array<[keyof ThemeColorTokens, string]> = [
19	  ["background", "--background"],
20	  ["foreground", "--foreground"],
21	  ["card", "--card"],
22	  ["cardForeground", "--card-foreground"],
23	  ["popover", "--popover"],
24	  ["popoverForeground", "--popover-foreground"],
25	  ["primary", "--primary"],
26	  ["primaryForeground", "--primary-foreground"],
27	  ["secondary", "--secondary"],
28	  ["secondaryForeground", "--secondary-foreground"],
29	  ["muted", "--muted"],
30	  ["mutedForeground", "--muted-foreground"],
31	  ["accent", "--accent"],
32	  ["accentForeground", "--accent-foreground"],
33	  ["border", "--border"],
34	  ["input", "--input"],
35	  ["ring", "--ring"],
36	  ["destructive", "--destructive"],
37	  ["destructiveForeground", "--destructive-foreground"],
38	  ["info", "--info"],
39	  ["infoForeground", "--info-foreground"],
40	  ["success", "--success"],
41	  ["successForeground", "--success-foreground"],
42	  ["warning", "--warning"],
43	  ["warningForeground", "--warning-foreground"],
44	  ["sidebar", "--sidebar"],
45	  ["sidebarForeground", "--sidebar-foreground"],
46	  ["sidebarBorder", "--sidebar-border"],
47	];
48	
49	type ThemeSnapshot = {
50	  preference: ThemePreference;
51	  systemDark: boolean;
52	};
53	
54	let listeners: Array<() => void> = [];
55	let cachedSnapshot: ThemeSnapshot | null = null;
56	
57	function emitChange() {
58	  for (const listener of listeners) listener();
59	}
60	
61	function getSystemDark(): boolean {
62	  return window.matchMedia(MEDIA_QUERY).matches;
63	}
64	
65	/**
66	 * Read the stored preference with legacy migration:
67	 *   "light" → "t3-light", "dark" → "t3-dark"
68	 */
69	function getStored(): ThemePreference {
70	  const raw = localStorage.getItem(STORAGE_KEY);
71	  // Migrate values written by the previous implementation
72	  if (raw === "light") return "t3-light";
73	  if (raw === "dark") return "t3-dark";
74	  if (raw === "t3-light" || raw === "t3-dark" || raw === "t3-midnight" || raw === "system") {
75	    return raw;
76	  }
77	  return "system";
78	}
79	
80	/**
81	 * Apply a theme preference to the document by:
82	 *  1. Toggling the `.dark` class (needed by Tailwind dark: utilities and static CSS rules)
83	 *  2. Writing all color tokens as inline CSS custom properties on <html>
84	 *     (inline styles beat :root rules in the cascade, so this is flash-free)
85	 */
86	function applyTheme(preference: ThemePreference, systemDark: boolean, suppressTransitions = false) {
87	  if (suppressTransitions) {
