import { useCallback, useEffect, useSyncExternalStore } from "react";

import {
  type BuiltInTheme,
  type BuiltInThemeName,
  type ThemeColorTokens,
  type ThemePreference,
  resolveTheme,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/**
 * Maps each ThemeColorTokens field to the corresponding CSS custom property
 * name so we can apply them all as inline styles on <html>.
 */
const CSS_VAR_MAP: Array<[keyof ThemeColorTokens, string]> = [
  ["background", "--background"],
  ["foreground", "--foreground"],
  ["card", "--card"],
  ["cardForeground", "--card-foreground"],
  ["popover", "--popover"],
  ["popoverForeground", "--popover-foreground"],
  ["primary", "--primary"],
  ["primaryForeground", "--primary-foreground"],
  ["secondary", "--secondary"],
  ["secondaryForeground", "--secondary-foreground"],
  ["muted", "--muted"],
  ["mutedForeground", "--muted-foreground"],
  ["accent", "--accent"],
  ["accentForeground", "--accent-foreground"],
  ["border", "--border"],
  ["input", "--input"],
  ["ring", "--ring"],
  ["destructive", "--destructive"],
  ["destructiveForeground", "--destructive-foreground"],
  ["info", "--info"],
  ["infoForeground", "--info-foreground"],
  ["success", "--success"],
  ["successForeground", "--success-foreground"],
  ["warning", "--warning"],
  ["warningForeground", "--warning-foreground"],
  ["sidebar", "--sidebar"],
  ["sidebarForeground", "--sidebar-foreground"],
  ["sidebarBorder", "--sidebar-border"],
];

type ThemeSnapshot = {
  preference: ThemePreference;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let cachedSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Read the stored preference with legacy migration:
 *   "light" → "t3-light", "dark" → "t3-dark"
 */
function getStored(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  // Migrate values written by the previous implementation
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "t3-light" || raw === "t3-dark" || raw === "t3-midnight" || raw === "system") {
    return raw;
  }
  return "system";
}

/**
 * Apply a theme preference to the document by:
 *  1. Toggling the `.dark` class (needed by Tailwind dark: utilities and static CSS rules)
 *  2. Writing all color tokens as inline CSS custom properties on <html>
 *     (inline styles beat :root rules in the cascade, so this is flash-free)
 */
function applyTheme(preference: ThemePreference, systemDark: boolean, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = resolveTheme(preference, systemDark);
  const el = document.documentElement;

  el.classList.toggle("dark", theme.isDark);
  el.style.colorScheme = theme.isDark ? "dark" : "light";

  for (const [key, cssVar] of CSS_VAR_MAP) {
    el.style.setProperty(cssVar, theme.tokens[key]);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash before React hydrates
applyTheme(getStored(), getSystemDark());

function getSnapshot(): ThemeSnapshot {
  const preference = getStored();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    cachedSnapshot !== null &&
    cachedSnapshot.preference === preference &&
    cachedSnapshot.systemDark === systemDark
  ) {
    return cachedSnapshot;
  }

  cachedSnapshot = { preference, systemDark };
  return cachedSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Re-apply when system dark-mode preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", mq.matches, true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Re-apply when another tab writes to localStorage
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), getSystemDark(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { preference, systemDark } = snapshot;

  const resolvedThemeData: BuiltInTheme = resolveTheme(preference, systemDark);
  const resolvedTheme: BuiltInThemeName = resolvedThemeData.name;

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, getSystemDark(), true);
    emitChange();
  }, []);

  // Keep DOM in sync when the snapshot changes (e.g. after a storage migration)
  useEffect(() => {
    applyTheme(preference, systemDark);
  }, [preference, systemDark]);

  return { theme: preference, setTheme, resolvedTheme, resolvedThemeData } as const;
}

